import { useState } from 'react';

let renderCount = 0;

function BatchDemo() {
  renderCount++;
  const [a, setA] = useState(0);
  const [b, setB] = useState(0);
  const [c, setC] = useState(0);

  console.log('Render #', renderCount, '  a:', a, 'b:', b, 'c:', c);

  function handleClick() {
    setA(a + 1);
    setB(b + 10);
    setC(c + 100);
    // React 18: ONE render after this handler completes
    // renderCount increments by 1, not 3
  }

  return (
    <div>
      <p>{a} + {b} + {c} = {a + b + c}</p>
      <button onClick={handleClick}>Update all three</button>
    </div>
  );
}

// React 17: NOT batched — 2 renders from setTimeout
// React 18: batched — 1 render from setTimeout
function AsyncBatchDemo() {
  const [count, setCount] = useState(0);
  const [flag, setFlag] = useState(false);

  function handleClick() {
    setTimeout(() => {
      setCount(c => c + 1); // React 17: render here
      setFlag(f => !f);     // React 17: render here too
      // React 18: both enqueued, single render at end of setTimeout
    }, 0);
  }

  console.log('render', { count, flag });
  return <button onClick={handleClick}>Go</button>;
}

// Batching in async/await (React 18)
async function handleSubmit() {
  const data = await fetchUser(userId);
  // React 18: these are batched even after await
  setUser(data.user);
  setLoading(false);
  setError(null);
  // Single re-render with all three values updated
}

import { flushSync } from 'react-dom';

function MeasureDemo() {
  const [expanded, setExpanded] = useState(false);
  const [height, setHeight] = useState(0);
  const divRef = useRef(null);

  function handleExpand() {
    flushSync(() => {
      setExpanded(true); // DOM is updated synchronously before flushSync returns
    });
    // Now safe to measure — the expanded DOM is already in place
    setHeight(divRef.current.offsetHeight);
  }

  return <div ref={divRef}>{expanded ? 'Big content' : 'Small'}</div>;
}

function Counter() {
  const [count, setCount] = useState(0);

  function handleTripleIncrement() {
    // Using snapshot values — WRONG: all three read count=0
    setCount(count + 1); // queues: set count to 0+1 = 1
    setCount(count + 1); // queues: set count to 0+1 = 1 (overwrites!)
    setCount(count + 1); // queues: set count to 0+1 = 1 (overwrites!)
    // Result: count becomes 1, not 3
  }

  function handleFunctionalTriple() {
    // Using functional updaters — CORRECT: each receives previous queued value
    setCount(prev => prev + 1); // prev=0 → queues 1
    setCount(prev => prev + 1); // prev=1 → queues 2
    setCount(prev => prev + 1); // prev=2 → queues 3
    // Result: count becomes 3
  }

  return (
    <>
      <p>Count: {count}</p>
      <button onClick={handleTripleIncrement}>Snapshot +3 (broken)</button>
      <button onClick={handleFunctionalTriple}>Functional +3 (correct)</button>
    </>
  );
}

function MixedDemo() {
  const [count, setCount] = useState(5);

  function handleClick() {
    setCount(count + 1);        // snapshot(5)+1 → queues literal 6
    setCount(prev => prev * 2); // functional: receives 6, queues 12
    setCount(count + 100);      // snapshot(5)+100 → queues literal 105
    // Final value: 105 (last literal wins over the functional result)
  }

  return <button onClick={handleClick}>{count}</button>;
}

import { startTransition, useState } from 'react';

function SearchInput() {
  const [inputValue, setInputValue] = useState('');
  const [query, setQuery] = useState('');

  function handleChange(e) {
    // Urgent: renders the input immediately
    setInputValue(e.target.value);

    // Low-priority: React batches across keystrokes and renders SearchResults
    // only when typing pauses — intermediate query values are skipped
    startTransition(() => {
      setQuery(e.target.value);
    });
  }

  return (
    <>
      <input value={inputValue} onChange={handleChange} />
      <SearchResults query={query} />
    </>
  );
}

class ClassCounter extends React.Component {
  state = { a: 0, b: 0 };

  handleClick = () => {
    // Both updates batched — one render
    this.setState({ a: this.state.a + 1 });
    this.setState({ b: this.state.b + 1 });

    // this.state.a is still 0 here — not yet applied
    console.log(this.state.a); // prints 0, not 1

    // Functional form for composing through the queue:
    this.setState(prev => ({ a: prev.a + 1 }));
    this.setState(prev => ({ b: prev.b + 1 }));
  };
}

