// Record → trigger action → stop → inspect flame graph
// Each commit bar = one batch of DOM changes
// If you see two bars for one click, batching is not working

// Or use a render counter in development:
let renderCount = 0;
function MyComponent() {
  if (process.env.NODE_ENV === 'development') renderCount++;
  console.log('render', renderCount);
  // ...
}

// Anti-pattern: three separate pieces of state, all updated together
function Form() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [submitting, setSubmitting] = useState(false);

  async function handleSubmit() {
    setSubmitting(true);
    await submitForm({ name, email });
    setName('');
    setEmail('');
    setSubmitting(false);
    // React 18: 3 setters → 1 render after await (automatic batching)
  }
}

// Better pattern: single state object for tightly coupled fields
function Form() {
  const [form, setForm] = useState({ name: '', email: '', submitting: false });

  async function handleSubmit() {
    setForm(prev => ({ ...prev, submitting: true }));
    await submitForm(form);
    setForm({ name: '', email: '', submitting: false });
    // One setter → always one render, simpler to reason about
  }
}

const CounterContext = React.createContext(null);

function Parent() {
  const [parentCount, setParentCount] = useState(0);

  function handleClick() {
    setParentCount(c => c + 1); // parent update
    // If context consumers also call setState, all batched in React 18
  }

  return (
    <CounterContext.Provider value={parentCount}>
      <Child onParentClick={handleClick} />
    </CounterContext.Provider>
  );
}

function Child({ onParentClick }) {
  const [childCount, setChildCount] = useState(0);

  function handleClick() {
    onParentClick();           // triggers parent setState
    setChildCount(c => c + 1); // triggers child setState
    // React 18: both batched — parent and child re-render once together
  }

  return <button onClick={handleClick}>Click</button>;
}

import { render, screen, fireEvent } from '@testing-library/react';
import { act } from 'react';

test('batched updates render once', async () => {
  const renders = [];
  function Tracker() {
    renders.push(Date.now());
    const [a, setA] = useState(0);
    const [b, setB] = useState(0);
    return (
      <button onClick={() => { setA(1); setB(2); }}>
        {a},{b}
      </button>
    );
  }

  render(<Tracker />);
  const initialRenders = renders.length;

  await act(async () => {
    fireEvent.click(screen.getByRole('button'));
  });

  // Exactly one additional render — batching worked
  expect(renders.length - initialRenders).toBe(1);
  expect(screen.getByRole('button')).toHaveTextContent('1,2');
});

// Impure render — BAD: writes to external state during render
let lastRenderedCount;
function Counter() {
  const [count, setCount] = useState(0);
  lastRenderedCount = count; // side effect in render body!
  return <div>{count}</div>;
}

// Pure render — GOOD: reads and returns, no side effects
function Counter() {
  const [count, setCount] = useState(0);
  // lastRenderedCount would be updated in useEffect, not here
  useEffect(() => { lastRenderedCount = count; }, [count]);
  return <div>{count}</div>;
}
